body.script:
import { initializeApp } from "https://www.gstatic.com/firebasejs/12.9.0/firebase-app.js";
import { getFirestore, collection, getDocs, doc, getDoc, query, orderBy } from "https://www.gstatic.com/firebasejs/12.9.0/firebase-firestore.js";

// ==== FIREBASE CONFIG FROM YOUR PAGE ====
const firebaseConfig = {
  apiKey: "AIzaSyAViNqylDfCnXd6iyzChJiTgZaI18cU9zw",
  authDomain: "itzsos-labs.firebaseapp.com",
  projectId: "itzsos-labs",
  storageBucket: "itzsos-labs.firebasestorage.app",
  messagingSenderId: "1012826517121",
  appId: "1:1012826517121:web:abaf58ebce7f15cfc86780"
};

const app = initializeApp(firebaseConfig);
const db = getFirestore(app);

// ==== DOM ELEMENTS ====
const stageContainer = document.getElementById('stage-container');
const hintText = document.getElementById('hint-text');
const answerInput = document.getElementById('answer-input');
const feedback = document.getElementById('feedback');
const showHintBtn = document.getElementById('show-hint');

let stagesData = [];
let currentStage = 0;

// ==== LOAD STAGES ====
async function loadStages() {
  const q = query(collection(db, 'stages'), orderBy('stageNumber'));
  const snapshot = await getDocs(q);
  snapshot.forEach(docSnap => {
    stagesData.push({ id: docSnap.id, ...docSnap.data() });
  });
  loadStage(currentStage);
}

function loadStage(index){
  if(index >= stagesData.length){
    stageContainer.innerHTML = "
🎉 Congratulations! All stages completed!";
    hintText.textContent = "";
    feedback.textContent = "";
    answerInput.style.display = "none";
    showHintBtn.style.display = "none";
    return;
  }
  const stage = stagesData[index];
  stageContainer.innerHTML = `
Stage ${stage.stageNumber}
${stage.description}`;
  hintText.textContent = "";
  feedback.textContent = "";
  answerInput.value = "";
}

showHintBtn.addEventListener('click', () => {
  hintText.textContent = stagesData[currentStage].hint || "No hint available.";
});

document.getElementById('submit-answer').addEventListener('click', async () => {
  const stage = stagesData[currentStage];
  const answer = answerInput.value.trim();
  if(!answer) return;

  const docRef = doc(db, 'stages', stage.id);
  const docSnap = await getDoc(docRef);

  if(docSnap.exists() && docSnap.data().answer.toLowerCase() === answer.toLowerCase()){
    feedback.textContent = "✅ Correct! Next stage loading...";
    currentStage++;
    setTimeout(()=>loadStage(currentStage), 800);
  } else {
    feedback.textContent = "❌ Incorrect, try again!";
  }
});

// INIT
loadStages();
